// Embedded images - no images folder needed
(function(){
  var imgs = {
    "images/hero-debbies.jpg": "data:image/jpeg;base64,",
    "images/debbies-logo.jpg": "data:image/jpeg;base64,",
    "images/room-executive.jpg": "data:image/jpeg;base64,",
    "images/room-deluxe.jpg": "data:image/jpeg;base64,",
    "images/room-presidential.jpg": "data:image/jpeg;base64,",
    "images/apartment-suite.jpg": "data:image/jpeg;base64,",
    "images/event-hall.jpg": "data:image/jpeg;base64,",
    "images/conference.jpg": "data:image/jpeg;base64,",
    "images/restaurant.jpg": "data:image/jpeg;base64,",
    "images/cuisine.jpg": "data:image/jpeg;base64,",
    "images/pool.jpg": "data:image/jpeg;base64,",
    "images/gym.jpg": "data:image/jpeg;base64,",
    "images/lounge.jpg": "data:image/jpeg;base64,",
    "images/outdoor-lounge.jpg": "data:image/jpeg;base64,",
  };
  document.querySelectorAll('img').forEach(function(img){
    var src = img.getAttribute('src');
    if(imgs[src]) img.src = imgs[src];
  });
  // Also fix CSS background-image inline styles
  document.querySelectorAll('[style]').forEach(function(el){
    var s = el.getAttribute('style');
    if(!s) return;
    var changed = s;
    Object.keys(imgs).forEach(function(k){
      changed = changed.split('url(\"'+k+'\"').join('url(\"'+imgs[k]+'\"');
      changed = changed.split("url('"+k+"'").join("url('"+imgs[k]+"'");
      changed = changed.split('url('+k+')').join('url('+imgs[k]+')');
    });
    if(changed !== s) el.setAttribute('style', changed);
  });
})();